import{_ as a,c as i,o as e,aj as s,aQ as r,aR as l,aS as d,aT as p,aU as n,aV as h,aW as o,aX as c,aY as g,aZ as m}from"./chunks/framework.CoirRWyn.js";const y=JSON.parse('{"title":"2.1 用AI头脑风暴 [Brainstorming with AI]","description":"","frontmatter":{},"headers":[],"relativePath":"module_2/2.1用AI头脑风暴[Brainstorming with AI].md","filePath":"module_2/2.1用AI头脑风暴[Brainstorming with AI].md"}'),_={name:"module_2/2.1用AI头脑风暴[Brainstorming with AI].md"};function b(k,t,A,I,x,u){return e(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="_2-1-用ai头脑风暴-brainstorming-with-ai" tabindex="-1">2.1 用AI头脑风暴 [Brainstorming with AI] <a class="header-anchor" href="#_2-1-用ai头脑风暴-brainstorming-with-ai" aria-label="Permalink to “2.1 用AI头脑风暴 [Brainstorming with AI]”">​</a></h1><blockquote><p><strong>主题：</strong> 用 AI 扩展想法空间，快速获得多个候选方向，再由人进行筛选、判断和深化。</p></blockquote><p><img src="'+r+'" alt="alt text"></p><p>AI 很适合做头脑风暴，因为它可以在很短时间内给出大量选项。人类在思考一个问题时，容易受已有经验、常见案例和个人视角限制，而 AI 可以快速从不同身份、不同场景、不同策略出发，补充更多方向。</p><p>但是，AI 生成的想法不等于天然更有创造力。模型通常会优先输出训练数据中更常见、更稳妥、更符合平均预期的答案。因此，AI 头脑风暴的重点不是“让 AI 替你决定”，而是“让 AI 帮你扩大可选空间”。</p><p><img src="'+l+'" alt="alt text"></p><p>高质量头脑风暴首先需要上下文。只说“帮我制定健身计划”，AI 往往会给出普通计划；如果补充年龄、训练经验、器械条件、每天可用时间、受伤情况和个人偏好，AI 才能生成更贴近真实情况的建议。</p><p><img src="'+d+'" alt="alt text"></p><p>AI 的输出具有一定随机性。同一个问题，多次询问可能得到不同答案。常见回答通常出现概率更高，独特回答概率更低。因此，如果希望获得更有创意的结果，需要明确要求 AI 跳出常规方案。</p><p><img src="'+p+'" alt="alt text"></p><p>AI 默认偏向常识性回答。在事实问答中，这种倾向是优点，因为用户需要稳定、可靠的信息；但在头脑风暴中，过度常识化会限制创意，导致答案“正确但普通”。</p><p><img src="'+n+'" alt="alt text"></p><p>高质量想法通常来自“具体上下文 + 多样化要求”。例如，要求 AI 同时给出常规方案、低成本方案、反直觉方案、适合学生完成的方案和适合商业落地的方案，可以显著提升结果的可选性。</p><h2 id="头脑风暴提示词应包含的信息" tabindex="-1">头脑风暴提示词应包含的信息 <a class="header-anchor" href="#头脑风暴提示词应包含的信息" aria-label="Permalink to “头脑风暴提示词应包含的信息”">​</a></h2><table tabindex="0"><thead><tr><th>信息类型</th><th>作用</th><th>示例</th></tr></thead><tbody><tr><td>背景</td><td>让 AI 知道任务发生在什么场景</td><td>我正在做一个校园 AI 创新项目</td></tr><tr><td>目标</td><td>说明最终想解决什么问题</td><td>想设计一个能落地的小工具</td></tr><tr><td>受众</td><td>说明想法服务谁</td><td>面向大学生、老师或比赛评委</td></tr><tr><td>限制</td><td>防止方案不现实</td><td>开发周期 2 周，预算低，不能依赖复杂硬件</td></tr><tr><td>偏好</td><td>控制想法风格</td><td>希望方案实用、有传播性、容易展示</td></tr><tr><td>输出形式</td><td>规定结果格式</td><td>给我 10 个方向，并按可行性排序</td></tr></tbody></table><h2 id="让-ai-生成更多样的选项" tabindex="-1">让 AI 生成更多样的选项 <a class="header-anchor" href="#让-ai-生成更多样的选项" aria-label="Permalink to “让 AI 生成更多样的选项”">​</a></h2><p><img src="'+h+'" alt="alt text"></p><p>AI 适合先给多个策略，再由用户根据现实情况筛选。例如在债务规划中，AI 可以分别提出“优先降低高息负债”“优先保证现金流”“优先处理家庭关系”等不同路径。每种路径背后都有不同价值取舍，不能只看一个表面答案。</p><p><img src="'+o+'" alt="alt text"></p><p>第一轮结果通常不是终稿。用户可以告诉 AI 哪些方案太保守、哪些不可执行、哪些方向值得展开，让 AI 基于反馈继续生成下一版。</p><p><img src="'+c+'" alt="alt text"></p><p>迭代的价值在于把“普通答案”逐步推向“更符合个人限制的答案”。用户反馈越具体，AI 下一轮结果越可能接近真实需求。</p><p><img src="'+g+'" alt="alt text"></p><p>当某个方案看起来有潜力时，不要立刻结束，可以继续要求 AI 补充执行步骤、风险、成本、失败原因和替代方案。</p><p><img src="'+m+'" alt="alt text"></p><p>可以把 AI 头脑风暴理解为一个公式：</p><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>上下文 + 多个选项 + 多轮迭代 = 更高质量的想法</span></span></code></pre></div><h2 id="可直接套用的-prompt-模板" tabindex="-1">可直接套用的 Prompt 模板 <a class="header-anchor" href="#可直接套用的-prompt-模板" aria-label="Permalink to “可直接套用的 Prompt 模板”">​</a></h2><h3 id="模板-1-通用头脑风暴" tabindex="-1">模板 1：通用头脑风暴 <a class="header-anchor" href="#模板-1-通用头脑风暴" aria-label="Permalink to “模板 1：通用头脑风暴”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>我想围绕【主题】做头脑风暴。背景是【背景】，目标是【目标】，受众是【受众】。限制条件包括【时间/预算/技术/资源限制】。请先给我 20 个候选方向，并按“实用性、创新性、可执行性”进行简单标注。</span></span></code></pre></div><h3 id="模板-2-多角度发散" tabindex="-1">模板 2：多角度发散 <a class="header-anchor" href="#模板-2-多角度发散" aria-label="Permalink to “模板 2：多角度发散”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>请从 5 个角度重新思考这个问题：用户需求、低成本实现、反常识方案、长期价值、展示效果。每个角度给出 5 个想法，并说明适合什么场景。</span></span></code></pre></div><h3 id="模板-3-从发散到收敛" tabindex="-1">模板 3：从发散到收敛 <a class="header-anchor" href="#模板-3-从发散到收敛" aria-label="Permalink to “模板 3：从发散到收敛”">​</a></h3><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>请根据以下标准评估这些想法：可执行性、成本、创新性、风险、用户价值。每项按 1-5 分评价，并推荐最值得继续推进的 3 个方向。</span></span></code></pre></div><h2 id="小结" tabindex="-1">小结 <a class="header-anchor" href="#小结" aria-label="Permalink to “小结”">​</a></h2><p>AI 头脑风暴的重点不是一次生成最终答案，而是帮助用户扩大思路。第一轮结果通常只是起点，真正有效的做法是补充上下文、要求多样化、持续反馈、不断迭代。</p><hr>',37)])])}const P=a(_,[["render",b]]);export{y as __pageData,P as default};
